import*as React from"react";import{animate}from"../../lib/animate.js";import{cubicBezier}from"../../lib/fx.js";import{ANIMATION_DURATION}from"./constants.js";const TIMING_FUNCTION=cubicBezier(.8,1);function useSlideAnimation(){const n=React.useRef([]);return{getAnimateFunction:function(t){return()=>{animate({duration:ANIMATION_DURATION,timing:TIMING_FUNCTION,animationQueue:n.current,draw:t})}},addToAnimationQueue:function(t){n.current.push(t)},startAnimation:function(){1===n.current.length&&n.current[0]()}}}export{useSlideAnimation};